 421→### Task 3: Create System Config Table
 422→
 423→**Files:**
 424→- Modify: `backend/src/services/database.ts`
 425→- Test: Manual verification
 426→
 427→**Step 1: Add system_config table creation**
 428→
 429→```typescript
 430→const createSystemConfigTable = `
 431→  CREATE TABLE IF NOT EXISTS system_config (
 432→    key TEXT PRIMARY KEY,
 433→    value TEXT NOT NULL,
 434→    description TEXT,
 435→    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
 436→    updated_by INTEGER,
 437→    FOREIGN KEY (updated_by) REFERENCES users(id) ON DELETE SET NULL
 438→  )
 439→`;
 440→```
 441→
 442→**Step 2: Add to serialization**
 443→
 444→```typescript
 445→this.db.run(createSystemConfigTable);
 446→```
 447→
 448→**Step 3: Insert default config values**
 449→
 450→Add method to initialize default config:
 451→
 452→```typescript
 453→private initializeSystemConfig(): void {
 454→  const defaults = [
 455→    { key: 'quota_max_products', value: '100', description: 'Max products per user' },
 456→    { key: 'quota_max_lists', value: '20', description: 'Max lists per user' },
 457→    { key: 'scheduler_enabled', value: 'true', description: 'Enable automatic price updates' },
 458→    { key: 'scheduler_cron', value: '0 0 * * *', description: 'Cron schedule for price updates' }
 459→  ];
 460→
 461→  defaults.forEach(config => {
 462→    const sql = `
 463→      INSERT OR IGNORE INTO system_config (key, value, description)
 464→      VALUES (?, ?, ?)
 465→    `;
 466→    this.db.run(sql, [config.key, config.value, config.description]);
 467→  });
 468→}
 469→```
 470→
 471→Call this in `initialize()` after table creation:
 472→
 473→```typescript
 474→this.initializeSystemConfig();
 475→```
 476→
 477→**Step 4: Add config CRUD methods**
 478→
 479→```typescript
 480→async getConfig(key: string): Promise<string | null> {
 481→  return new Promise((resolve, reject) => {
 482→    const sql = 'SELECT value FROM system_config WHERE key = ?';
 483→    this.db.get(sql, [key], (err, row: any) => {
 484→      if (err) {
 485→        reject(err);
 486→        return;
 487→      }
 488→      resolve(row?.value || null);
 489→    });
