1179→      SELECT
1180→        COUNT(DISTINCT p.id) as product_count,
1181→        COUNT(DISTINCT l.id) as list_count,
1182→        COUNT(DISTINCT ph.id) as price_history_count
1183→      FROM users u
1184→      LEFT JOIN products p ON u.id = p.user_id
1185→      LEFT JOIN user_lists l ON u.id = l.user_id
1186→      LEFT JOIN price_history ph ON p.id = ph.product_id
1187→      WHERE u.id = ?
1188→      GROUP BY u.id
1189→    `;
1190→    this.db.get(sql, [userId], (err, row: any) => {
1191→      if (err) {
1192→        reject(err);
1193→        return;
1194→      }
1195→      resolve({
1196→        product_count: row?.product_count || 0,
1197→        list_count: row?.list_count || 0,
1198→        price_history_count: row?.price_history_count || 0
1199→      });
1200→    });
1201→  });
1202→}
1203→
1204→async getSystemStats(): Promise<SystemStats> {
1205→  return new Promise((resolve, reject) => {
1206→    const sql = `
1207→      SELECT
1208→        (SELECT COUNT(*) FROM users) as total_users,
1209→        (SELECT COUNT(*) FROM users WHERE role = 'ADMIN') as total_admins,
1210→        (SELECT COUNT(*) FROM users WHERE is_disabled = 1) as disabled_users,
1211→        (SELECT COUNT(*) FROM products) as total_products,
1212→        (SELECT COUNT(DISTINCT user_id) FROM products) as active_users,
1213→        (SELECT COUNT(*) FROM price_history) as total_price_history
1214→    `;
1215→    this.db.get(sql, [], (err, row: any) => {
1216→      if (err) {
1217→        reject(err);
1218→        return;
1219→      }
1220→      resolve({
1221→        total_users: row.total_users,
1222→        total_admins: row.total_admins,
1223→        disabled_users: row.disabled_users,
1224→        total_products: row.total_products,
1225→        active_users: row.active_users,
1226→        total_price_history: row.total_price_history
1227→      });
1228→    });
1229→  });
1230→}
1231→```
