2604→async checkProductQuota(userId: number): Promise<{ allowed: boolean; current: number; max: number }> {
2605→  return new Promise((resolve, reject) => {
2606→    const sql = 'SELECT COUNT(*) as count FROM products WHERE user_id = ?';
2607→    this.db.get(sql, [userId], async (err, row: any) => {
2608→      if (err) {
