2614→      const maxConfig = await this.getConfig('quota_max_products');
2615→      const max = maxConfig ? parseInt(maxConfig) : 100;
2616→
2617→      resolve({
2618→        allowed: current < max,
2619→        current,
2620→        max
2621→      });
2622→    });
