2992→export function validateUsername(username: string): { valid: boolean; error?: string } {
2993→  if (!username || username.length < 3) {
2994→    return { valid: false, error: 'Username must be at least 3 characters' };
2995→  }
2996→  if (username.length > 50) {
2997→    return { valid: false, error: 'Username must be less than 50 characters' };
2998→  }
2999→  if (!/^[a-zA-Z0-9_-]+$/.test(username)) {
3000→    return { valid: false, error: 'Username can only contain letters, numbers, hyphens, and underscores' };
3001→  }
3002→  return { valid: true };
3003→}
3004→
3005→export function validatePassword(password: string): { valid: boolean; error?: string } {
3006→  if (!password || password.length < 6) {
3007→    return { valid: false, error: 'Password must be at least 6 characters' };
3008→  }
3009→  if (password.length > 100) {
3010→    return { valid: false, error: 'Password must be less than 100 characters' };
3011→  }
3012→  return { valid: true };
3013→}
3014→
3015→export function validateRole(role: string): { valid: boolean; error?: string } {
3016→  if (!['USER', 'ADMIN'].includes(role)) {
3017→    return { valid: false, error: 'Role must be either USER or ADMIN' };
3018→  }
3019→  return { valid: true };
3020→}
3021→
3022→export function validateConfigValue(key: string, value: string): { valid: boolean; error?: string } {
3023→  switch (key) {
3024→    case 'quota_max_products':
3025→    case 'quota_max_lists':
3026→      const num = parseInt(value);
3027→      if (isNaN(num) || num < 0 || num > 10000) {
3028→        return { valid: false, error: 'Value must be a number between 0 and 10000' };
3029→      }
3030→      break;
3031→    case 'scheduler_enabled':
3032→      if (value !== 'true' && value !== 'false') {
3033→        return { valid: false, error: 'Value must be true or false' };
3034→      }
3035→      break;
3036→    case 'scheduler_cron':
3037→      // Basic cron validation - 5 parts separated by space
3038→      if (!/^[0-9,*/-]+\s+[0-9,*/-]+\s+[0-9,*/-]+\s+[0-9,*/-]+\s+[0-9,*/-]+$/.test(value)) {
3039→        return { valid: false, error: 'Invalid cron expression' };
3040→      }
3041→      break;
3042→  }
3043→  return { valid: true };
3044→}
