import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { SystemConfig } from '../../types';
import { adminApi } from '../../services/api';

export function SystemConfig() {
  const { t } = useTranslation();
  const [config, setConfig] = useState<SystemConfig[]>([]);
  const [loading, setLoading] = useState(true);
  const [editingKey, setEditingKey] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');

  useEffect(() => {
    loadConfig();
  }, []);

  const loadConfig = async () => {
    try {
      setLoading(true);
      const data = await adminApi.getConfig();
      setConfig(data);
    } catch (error) {
      console.error('Failed to load config:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleUpdate = async (key: string, value: string) => {
    try {
      await adminApi.updateConfig(key, value);
      setEditingKey(null);
      loadConfig();
    } catch (error: any) {
      alert(error.message || t('admin.config.failedToUpdate'));
    }
  };

  const handleEdit = (item: SystemConfig) => {
    setEditingKey(item.key);
    setEditValue(item.value);
  };

  const handleCancel = () => {
    setEditingKey(null);
    setEditValue('');
  };

  if (loading) {
    return <div className="loading">{t('common.loading')}</div>;
  }

  return (
    <div className="system-config">
      <h2>{t('admin.config.title')}</h2>

      <table className="admin-table">
        <thead>
          <tr>
            <th>{t('admin.config.key')}</th>
            <th>{t('admin.config.description')}</th>
            <th>{t('admin.config.value')}</th>
            <th>{t('admin.config.updatedAt')}</th>
            <th>{t('admin.config.actions')}</th>
          </tr>
        </thead>
        <tbody>
          {config.map((item) => (
            <tr key={item.key}>
              <td><code>{item.key}</code></td>
              <td>{item.description}</td>
              <td>
                {editingKey === item.key ? (
                  <div className="edit-input">
                    <input
                      type="text"
                      value={editValue}
                      onChange={(e) => setEditValue(e.target.value)}
                    />
                    <button
                      className="btn btn-small btn-primary"
                      onClick={() => handleUpdate(item.key, editValue)}
                    >
                      {t('common.save')}
                    </button>
                    <button
                      className="btn btn-small"
                      onClick={handleCancel}
                    >
                      {t('common.cancel')}
                    </button>
                  </div>
                ) : (
                  <code>{item.value}</code>
                )}
              </td>
              <td>{new Date(item.updated_at).toLocaleString()}</td>
              <td>
                {editingKey !== item.key && (
                  <button
                    className="btn btn-small"
                    onClick={() => handleEdit(item)}
                  >
                    {t('admin.config.edit')}
                  </button>
                )}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
