export interface Category {
  id: number;
  name: string;
  level: number;
}

export interface CategoryTreeNode {
  id: number;
  name: string;
  children: { id: number; name: string }[];
}

export interface Product {
  id: number;
  asin: string;
  description: string;
  categories?: Category[];
  lists?: UserList[];
  created_at: string;
}

export interface PriceHistory {
  id: number;
  product_id: number;
  price: number;
  date: string;
  created_at: string;
}

export interface ProductWithPrice extends Product {
