import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useAuth } from '../contexts/AuthContext';
import { api } from '../services/api';

type TabType = 'channels' | 'rules' | 'history';

export function Notifications() {
  const { t } = useTranslation();
  const { user } = useAuth();
  const [activeTab, setActiveTab] = useState<TabType>('channels');
  const [loading, setLoading] = useState(false);
  const [showChannelForm, setShowChannelForm] = useState(false);
  const [showRuleForm, setShowRuleForm] = useState(false);
  const [editingChannel, setEditingChannel] = useState<any>(null);
  const [editingRule, setEditingRule] = useState<any>(null);

  // Load data based on active tab
  useEffect(() => {
    loadData();
  }, [activeTab]);

  const loadData = async () => {
    if (!user) return;
    setLoading(true);
    try {
      switch (activeTab) {
        case 'channels':
          await api.notifications.getChannels();
          break;
        case 'rules':
          await api.notifications.getRules();
          break;
        case 'history':
          await api.notifications.getHistory(100);
          break;
      }
    } catch (error) {
      console.error('Failed to load notifications:', error);
    } finally {
      setLoading(false);
    }
  };

  const channels = [
    { id: 1, type: 'email', name: 'Work Email', enabled: true },
    { id: 2, type: 'telegram', name: 'Personal Telegram', enabled: false },
  ];

  const rules = [
    { id: 1, type: 'lowest_in_days', enabled: true },
    { id: 2, type: 'below_threshold', enabled: false },
  ];

  const history = [
    { id: 1, status: 'sent', channel_name: 'Work Email', product_description: 'Test Product' },
  ];

  const handleCreateChannel = async (data: any) => {
    try {
      await api.notifications.createChannel(data);
      setShowChannelForm(false);
      loadData();
    } catch (error: any) {
      alert(t('notifications.channels.createFailed') + ': ' + (error as Error).message);
    }
  };

  const handleUpdateChannel = async (data: any) => {
    try {
      await api.notifications.updateChannel(editingChannel.id, data);
      setShowChannelForm(false);
      setEditingChannel(null);
      loadData();
    } catch (error: any) {
      alert(t('notifications.channels.updateFailed') + ': ' + (error as Error).message);
    }
  };

  const handleDeleteChannel = async (id: number) => {
    if (!confirm(t('notifications.channels.confirmDelete'))) return;
    try {
      await api.notifications.deleteChannel(id);
      loadData();
    } catch (error: any) {
      alert(t('notifications.channels.deleteFailed') + ': ' + (error as Error).message);
    }
  };

  const handleTestChannel = async (id: number) => {
    try {
      const result = await api.notifications.testChannel(id);
      if (result.success) {
        alert(t('notifications.channels.testSuccess'));
      } else {
        alert(t('notifications.channels.testFailed') + ': ' + result.error);
      }
    } catch (error: any) {
      alert('Failed to test channel: ' + error);
    }
  };

  const handleCreateRule = async (data: any) => {
    try {
      await api.notifications.createRule(data);
      setShowRuleForm(false);
      loadData();
    } catch (error: any) {
      alert(t('notifications.rules.createFailed') + ': ' + (error as Error).message);
    }
  };

  const handleUpdateRule = async (data: any) => {
    try {
      await api.notifications.updateRule(editingRule.id, data);
      setShowRuleForm(false);
      setEditingRule(null);
      loadData();
    } catch (error: any) {
      alert(t('notifications.rules.updateFailed') + ': ' + (error as Error).message);
    }
  };

  const handleDeleteRule = async (id: number) => {
    if (!confirm(t('notifications.rules.confirmDelete'))) return;
    try {
      await api.notifications.deleteRule(id);
      loadData();
    } catch (error: any) {
      alert(t('notifications.rules.deleteFailed') + ': ' + (error as Error).message);
    }
  };

  if (!user) {
    return <div className="notifications-section">
      <p>{t('notifications.pleaseLogin')}</p>
    </div>;
  }

  return (
    <div className="notifications-section">
      <h2>{t('notifications.title')}</h2>

      {/* Tabs */}
      <nav className="notifications-tabs">
        <button
          className={`notifications-tab ${activeTab === 'channels' ? 'active' : ''}`}
          onClick={() => setActiveTab('channels')}
        >
          {t('notifications.channels.title')}
        </button>
        <button
          className={`notifications-tab ${activeTab === 'rules' ? 'active' : ''}`}
          onClick={() => setActiveTab('rules')}
        >
          {t('notifications.rules.title')}
        </button>
        <button
          className={`notifications-tab ${activeTab === 'history' ? 'active' : ''}`}
          onClick={() => setActiveTab('history')}
        >
          {t('notifications.history.title')}
        </button>
      </nav>

      {loading ? (
        <div className="loading">{t('common.loading')}</div>
      ) : (
        <>
          {/* Channels Tab */}
          {activeTab === 'channels' && (
            <div className="notifications-content">
              <div className="notifications-header">
                <h3>{t('notifications.channels.title')}</h3>
                <button className="btn btn-primary" onClick={() => setShowChannelForm(true)}>
                  {t('notifications.channels.add')}
                </button>
              </div>

              <table className="notifications-table">
                <thead>
                  <tr>
                    <th>{t('notifications.channels.name')}</th>
                    <th>{t('notifications.channels.type')}</th>
                    <th>{t('notifications.channels.enabled')}</th>
                    <th>{t('notifications.channels.actions')}</th>
                  </tr>
                </thead>
                <tbody>
                  {channels.map((channel: any) => (
                    <tr key={channel.id}>
                      <td>{channel.name}</td>
                      <td>{t(`notifications.channels.type.${channel.type}`)}</td>
                      <td>
                        <button
                          className={`toggle-button ${channel.enabled ? 'on' : 'off'}`}
                          onClick={() => handleUpdateChannel(channel.id, { enabled: !channel.enabled })}
                        >
                          {channel.enabled ? '🟢' : '⚪'}
                        </button>
                      </td>
                      <td>
                        <button className="btn btn-small" onClick={() => setEditingChannel(channel)}>
                          {t('notifications.channels.edit')}
                        </button>
                        <button className="btn btn-small btn-danger" onClick={() => handleDeleteChannel(channel.id)}>
                          {t('common.delete')}
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}

          {/* Global Rules Tab */}
          {activeTab === 'rules' && (
            <div className="notifications-content">
              <div className="notifications-header">
                <h3>{t('notifications.rules.title')}</h3>
                <button className="btn btn-primary" onClick={() => setShowRuleForm(true)}>
                  {t('notifications.rules.add')}
                </button>
              </div>

              <table className="notifications-table">
                <thead>
                  <tr>
                    <th>{t('notifications.rules.type')}</th>
                    <th>{t('notifications.rules.params')}</th>
                    <th>{t('notifications.rules.channel')}</th>
                    <th>{t('notifications.rules.enabled')}</th>
                    <th>{t('notifications.rules.actions')}</th>
                  </tr>
                </thead>
                <tbody>
                  {rules.map((rule: any) => (
                    <tr key={rule.id}>
                      <td>{t(`notifications.rules.type.${rule.type}`)}</td>
                      <td>{JSON.stringify(rule.params)}</td>
                      <td>-</td>
                      <td>
                        <button
                          className={`toggle-button ${rule.enabled ? 'on' : 'off'}`}
                          onClick={() => handleUpdateRule(rule.id, { enabled: !rule.enabled })}
                        >
                          {rule.enabled ? '🟢' : '⚪'}
                        </button>
                      </td>
                      <td>
                        <button className="btn btn-small" onClick={() => setEditingRule(rule)}>
                          {t('notifications.rules.edit')}
                        </button>
                        <button className="btn btn-small btn-danger" onClick={() => handleDeleteRule(rule.id)}>
                          {t('common.delete')}
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}

          {/* History Tab */}
          {activeTab === 'history' && (
            <div className="notifications-content">
              <h3>{t('notifications.history.title')}</h3>
              <table className="notifications-table">
                <thead>
                  <tr>
                    <th>{t('notifications.history.date')}</th>
                    <th>{t('notifications.history.product')}</th>
                    <th>{t('notifications.history.trigger')}</th>
                    <th>{t('notifications.history.channel')}</th>
                    <th>{t('notifications.history.status')}</th>
                  </tr>
                </thead>
                <tbody>
                  {history.map((entry: any) => (
                    <tr key={entry.id}>
                      <td>{new Date(entry.created_at).toLocaleString()}</td>
                      <td>{entry.product_description || '-'}</td>
                      <td>{entry.trigger_type}</td>
                      <td>{entry.channel_name}</td>
                      <td>
                        <span className={`status-badge status-${entry.status}`}>
                          {entry.status}
                        </span>
                        {entry.error_message && <span className="error-text">: {entry.error_message}</span>}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </>
      )}

      {/* Channel Form Modal */}
      {showChannelForm && (
        <div className="modal-overlay">
          <div className="modal">
            <h3>{editingChannel ? t('notifications.channels.edit') : t('notifications.channels.add')}</h3>
            <form
              onSubmit={(e: React.FormEvent) => {
                e.preventDefault();
                if (editingChannel) {
                  handleUpdateChannel(editingChannel);
                } else {
                  handleCreateChannel({
                    type: 'email',
                    name: e.currentTarget.type.value,
                    config: {
                      smtp_host: e.currentTarget.smtp_host.value,
                      smtp_port: parseInt(e.currentTarget.smtp_port.value),
                      smtp_secure: e.currentTarget.smtp_secure.checked,
                      smtp_user: e.currentTarget.smtp_user.value,
                      smtp_pass: e.currentTarget.smtp_pass.value,
                      from_address: e.currentTarget.from_address.value,
                      to_address: e.currentTarget.to_address.value,
                    },
                  });
                }
              }}
            >
              <div className="form-group">
                <label>{t('notifications.channels.type')}</label>
                <select name="type" defaultValue={editingChannel?.type || 'email'}>
                  <option value="email">{t('notifications.channels.type.email')}</option>
                  <option value="telegram">{t('notifications.channels.type.telegram')}</option>
                  <option value="discord">{t('notifications.channels.type.discord')}</option>
                </select>
              </div>

              <div className="form-group">
                <label>{t('notifications.channels.name')}</label>
                <input type="text" name="name" defaultValue={editingChannel?.name || ''} required />
              </div>

              {/* Email config */}
              <div className="channel-config email-config">
                <div className="form-group">
                  <label>{t('notifications.channels.email.smtpHost')}</label>
                  <input type="text" name="smtp_host" defaultValue={editingChannel?.config?.smtp_host || ''} required />
                </div>
                <div className="form-group">
                  <label>{t('notifications.channels.email.smtpPort')}</label>
                  <input type="number" name="smtp_port" defaultValue={editingChannel?.config?.smtp_port || '587'} required />
                </div>
                <div className="form-group checkbox">
                  <label>
                    <input type="checkbox" name="smtp_secure" defaultChecked={true} />
                    {t('notifications.channels.email.smtpSecure')}
                  </label>
                </div>
                <div className="form-group">
                  <label>{t('notifications.channels.email.smtpUser')}</label>
                  <input type="text" name="smtp_user" defaultValue={editingChannel?.config?.smtp_user || ''} required />
                </div>
                <div className="form-group">
                  <label>{t('notifications.channels.email.smtpPass')}</label>
                  <input type="password" name="smtp_pass" defaultValue={editingChannel?.config?.smtp_pass || ''} required />
                </div>
                <div className="form-group">
                  <label>{t('notifications.channels.email.fromAddress')}</label>
                  <input type="email" name="from_address" defaultValue={editingChannel?.config?.from_address || ''} required />
                </div>
                <div className="form-group">
                  <label>{t('notifications.channels.email.toAddress')}</label>
                  <input type="email" name="to_address" defaultValue={editingChannel?.config?.to_address || ''} required />
                </div>
              </div>

              {/* Telegram config */}
              <div className="channel-config telegram-config" style={{ display: 'none' }}>
                <div className="form-group">
                  <label>{t('notifications.channels.telegram.botToken')}</label>
                  <input type="text" name="bot_token" defaultValue={editingChannel?.config?.bot_token || ''} />
                </div>
                <div className="form-group">
                  <label>{t('notifications.channels.telegram.chatId')}</label>
                  <input type="text" name="chat_id" defaultValue={editingChannel?.config?.chat_id || ''} />
                </div>
              </div>

              {/* Discord config */}
              <div className="channel-config discord-config" style={{ display: 'none' }}>
                <div className="form-group">
                  <label>{t('notifications.channels.discord.webhookUrl')}</label>
                  <input type="url" name="webhook_url" defaultValue={editingChannel?.config?.webhook_url || ''} />
                </div>
              </div>

              <div className="modal-actions">
                <button type="button" onClick={() => setShowChannelForm(false)}>
                  {t('common.cancel')}
                </button>
                <button type="submit" className="btn btn-primary">
                  {t('common.save')}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Rule Form Modal */}
      {showRuleForm && (
        <div className="modal-overlay">
          <div className="modal">
            <h3>{editingRule ? t('notifications.rules.edit') : t('notifications.rules.add')}</h3>
            <form
              onSubmit={(e: React.FormEvent) => {
                e.preventDefault();
                if (editingRule) {
                  handleUpdateRule(editingRule);
                } else {
                  handleCreateRule({
                    type: 'lowest_in_days',
                    params: JSON.stringify({ days: 30 }),
                    channel_id: 1,
                  });
                }
              }}
            >
              <div className="form-group">
                <label>{t('notifications.rules.type')}</label>
                <select name="type" defaultValue={editingRule?.type || 'lowest_in_days'}>
                  <option value="lowest_in_days">{t('notifications.rules.type.lowestInDays')}</option>
                  <option value="below_threshold">{t('notifications.rules.type.belowThreshold')}</option>
                  <option value="percentage_drop">{t('notifications.rules.type.percentageDrop')}</option>
                </select>
              </div>

              <div className="form-group">
                <label>{t('notifications.rules.params')}</label>
                <input type="text" name="params" defaultValue={editingRule?.params || ''} required />
              </div>

              <div className="form-group">
                <label>{t('notifications.rules.channel')}</label>
                <select name="channel_id" required>
                  <option value="">Select a channel...</option>
                  {channels.filter((c: any) => c.enabled).map((channel: any) => (
                    <option key={channel.id} value={channel.id}>
                      {channel.name}
                    </option>
                  ))}
                </select>
              </div>

              <div className="modal-actions">
                <button type="button" onClick={() => setShowRuleForm(false)}>
                  {t('common.cancel')}
                </button>
                <button type="submit" className="btn btn-primary">
                  {t('common.save')}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

