  1→import { useState, useEffect } from 'react';
  2→import { useTranslation } from 'react-i18next';
  3→import { api } from '../services/api';
  4→import { useAuth } from '../contexts/AuthContext';
  5→
  6→interface DatabaseInfo {
  7→  productCount: number;
  8→  databaseSize: number;
  9→  databaseSizeFormatted: string;
 10→}
 11→
 12→export function Config() {
 13→  const { t } = useTranslation();
 14→  const { user } = useAuth();
 15→  const [exporting, setExporting] = useState(false);
 16→  const [exportingDb, setExportingDb] = useState(false);
 17→  const [error, setError] = useState<string | null>(null);
 18→  const [dbInfo, setDbInfo] = useState<DatabaseInfo | null>(null);
 19→  const [loadingDbInfo, setLoadingDbInfo] = useState(true);
 20→  const [changingPassword, setChangingPassword] = useState(false);
 21→  const [passwordSuccess, setPasswordSuccess] = useState<string | null>(null);
 22→  const [passwordForm, setPasswordForm] = useState({
 23→    currentPassword: '',
 24→    newPassword: '',
 25→    confirmPassword: ''
 26→  });
 27→  const [activeSection, setActiveSection] = useState<string>('dashboard');
 28→  const [hasUnsavedChanges, setHasUnsavedChanges] = useState(false);
 29→  const [showConfirmDialog, setShowConfirmDialog] = useState(false);
 30→  const [pendingSection, setPendingSection] = useState<string | null>(null);
 31→
 32→  useEffect(() => {
 33→    loadDatabaseInfo();
 34→  }, []);
 35→
 36→  const loadDatabaseInfo = async () => {
 37→    try {
 38→      setLoadingDbInfo(true);
 39→      const info = await api.getDatabaseInfo();
 40→      setDbInfo(info);
 41→    } catch (err: any) {
 42→      console.error('Failed to load database info:', err);
 43→      setError(err.message || t('config.failedToLoad'));
 44→    } finally {
 45→      setLoadingDbInfo(false);
 46→    }
 47→  };
 48→
 49→  const handleExportASINs = async () => {
 50→    try {
 51→      setExporting(true);
 52→      setError(null);
 53→
 54→      const token = localStorage.getItem('authToken');
 55→      const response = await fetch('/api/config/export-asins', {
 56→        headers: token ? { 'Authorization': `Bearer ${token}` } : {},
 57→      });
 58→      
 59→      if (!response.ok) {
 60→        const errorData = await response.json();
 61→        throw new Error(errorData.error || t('config.failedToExport'));
 62→      }
 63→      
 64→      // Get the filename from Content-Disposition header or use default
 65→      const contentDisposition = response.headers.get('Content-Disposition');
 66→      const filename = contentDisposition 
 67→        ? contentDisposition.split('filename=')[1]?.replace(/"/g, '') 
 68→        : `amazon-tracked-asins-${new Date().toISOString().split('T')[0]}.csv`;
 69→      
 70→      // Get the CSV content
 71→      const csvContent = await response.text();
 72→      
 73→      // Create a blob and download
 74→      const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
 75→      const url = URL.createObjectURL(blob);
 76→      const link = document.createElement('a');
 77→      link.href = url;
 78→      link.download = filename;
 79→      document.body.appendChild(link);
 80→      link.click();
 81→      document.body.removeChild(link);
 82→      URL.revokeObjectURL(url);
 83→      
 84→    } catch (err: any) {
 85→      setError(err.message || t('config.failedToExport'));
 86→      console.error('Export error:', err);
 87→    } finally {
 88→      setExporting(false);
 89→    }
 90→  };
 91→
 92→  const handleExportDatabase = async () => {
 93→    try {
 94→      setExportingDb(true);
 95→      setError(null);
 96→      
 97→      const blob = await api.exportDatabase();
 98→      const filename = `products-database-${new Date().toISOString().split('T')[0]}.db`;
 99→      
100→      // Create download link
101→      const url = URL.createObjectURL(blob);
102→      const link = document.createElement('a');
103→      link.href = url;
104→      link.download = filename;
105→      document.body.appendChild(link);
106→      link.click();
107→      document.body.removeChild(link);
108→      URL.revokeObjectURL(url);
109→      
110→    } catch (err: any) {
111→      setError(err.message || t('config.failedToExportDatabase'));
112→      console.error('Database export error:', err);
113→    } finally {
114→      setExportingDb(false);
115→    }
116→  };
117→
118→  const handleChangePassword = async (e: React.FormEvent) => {
119→    e.preventDefault();
120→    setError(null);
121→    setPasswordSuccess(null);
122→
123→    if (passwordForm.newPassword !== passwordForm.confirmPassword) {
124→      setError(t('config.passwordMismatch'));
125→      return;
126→    }
127→
128→    if (passwordForm.newPassword.length < 6) {
129→      setError(t('config.passwordTooShort'));
130→      return;
131→    }
132→
