import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { api } from '../services/api';
import { useAuth } from '../contexts/AuthContext';

interface DatabaseInfo {
  productCount: number;
  databaseSize: number;
  databaseSizeFormatted: string;
}

export function Config() {
  const { t } = useTranslation();
  const { user } = useAuth();
  const [exporting, setExporting] = useState(false);
  const [exportingDb, setExportingDb] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [dbInfo, setDbInfo] = useState<DatabaseInfo | null>(null);
  const [loadingDbInfo, setLoadingDbInfo] = useState(true);
  const [changingPassword, setChangingPassword] = useState(false);
  const [passwordSuccess, setPasswordSuccess] = useState<string | null>(null);
  const [passwordForm, setPasswordForm] = useState({
    currentPassword: '',
    newPassword: '',
    confirmPassword: ''
  });
  const [activeSection, setActiveSection] = useState<string>('dashboard');
  const [hasUnsavedChanges, setHasUnsavedChanges] = useState(false);
  const [showConfirmDialog, setShowConfirmDialog] = useState(false);
  const [pendingSection, setPendingSection] = useState<string | null>(null);

  useEffect(() => {
    loadDatabaseInfo();
  }, []);

  const loadDatabaseInfo = async () => {
    try {
      setLoadingDbInfo(true);
      const info = await api.getDatabaseInfo();
      setDbInfo(info);
    } catch (err: any) {
      console.error('Failed to load database info:', err);
      setError(err.message || t('config.failedToLoad'));
    } finally {
      setLoadingDbInfo(false);
    }
  };

  const handleExportASINs = async () => {
    try {
      setExporting(true);
      setError(null);

      const token = localStorage.getItem('authToken');
      const response = await fetch('/api/config/export-asins', {
        headers: token ? { 'Authorization': `Bearer ${token}` } : {},
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || t('config.failedToExport'));
      }

      // Get the filename from Content-Disposition header or use default
      const contentDisposition = response.headers.get('Content-Disposition');
      const filename = contentDisposition 
        ? contentDisposition.split('filename=')[1]?.replace(/"/g, '') 
        : `amazon-tracked-asins-${new Date().toISOString().split('T')[0]}.csv`;

      // Get the CSV content
      const csvContent = await response.text();

      // Create a blob and download
      const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = filename;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);

    } catch (err: any) {
      setError(err.message || t('config.failedToExport'));
      console.error('Export error:', err);
    } finally {
      setExporting(false);
    }
  };

  const handleExportDatabase = async () => {
    try {
      setExportingDb(true);
      setError(null);

      const blob = await api.exportDatabase();
      const filename = `products-database-${new Date().toISOString().split('T')[0]}.db`;

      // Create download link
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = filename;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);

    } catch (err: any) {
      setError(err.message || t('config.failedToExportDatabase'));
      console.error('Database export error:', err);
    } finally {
      setExportingDb(false);
    }
  };

  const handleChangePassword = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setPasswordSuccess(null);

    if (passwordForm.newPassword !== passwordForm.confirmPassword) {
      setError(t('config.passwordMismatch'));
      return;
    }

    if (passwordForm.newPassword.length < 6) {
      setError(t('config.passwordTooShort'));
      return;
    }

    try {
      setChangingPassword(true);
      await api.changePassword(passwordForm.currentPassword, passwordForm.newPassword);
      setPasswordSuccess(t('config.passwordChanged'));
      setPasswordForm({
        currentPassword: '',
        newPassword: '',
        confirmPassword: ''
      });
      // Clear success message after 5 seconds
      setTimeout(() => {
        setPasswordSuccess(null);
      }, 5000);
    } catch (err: any) {
      setError(err.message || t('config.failedToChangePassword'));
    } finally {
      setChangingPassword(false);
    }
  };

  // Check if password form has unsaved changes
  useEffect(() => {
    const hasChanges = passwordForm.currentPassword !== '' || 
                      passwordForm.newPassword !== '' || 
                      passwordForm.confirmPassword !== '';
    setHasUnsavedChanges(hasChanges);
  }, [passwordForm]);

  const handleSectionChange = (sectionId: string) => {
    if (hasUnsavedChanges && activeSection === 'account') {
      setPendingSection(sectionId);
      setShowConfirmDialog(true);
    } else {
      setActiveSection(sectionId);
    }
  };

  const handleConfirmNavigation = () => {
    if (pendingSection) {
      setActiveSection(pendingSection);
      setPasswordForm({
        currentPassword: '',
        newPassword: '',
        confirmPassword: ''
      });
      setHasUnsavedChanges(false);
    }
    setShowConfirmDialog(false);
    setPendingSection(null);
  };

  const handleCancelNavigation = () => {
    setShowConfirmDialog(false);
    setPendingSection(null);
  };

  return (
    <div className="config-page">
      <h2>{t('config.title')}</h2>

      <div className="config-layout">
        <div className="config-sidebar">
          <nav className="config-nav">
            <button
              onClick={() => handleSectionChange('dashboard')}
              className={`config-nav-link ${activeSection === 'dashboard' ? 'active' : ''}`}
            >
              {t('config.dashboard')}
            </button>
            <button
              onClick={() => handleSectionChange('database')}
              className={`config-nav-link ${activeSection === 'database' ? 'active' : ''}`}
            >
              {t('config.database')}
            </button>
            <button
              onClick={() => handleSectionChange('data-export')}
              className={`config-nav-link ${activeSection === 'data-export' ? 'active' : ''}`}
            >
              {t('config.dataExport')}
            </button>
            <button
              onClick={() => handleSectionChange('account')}
              className={`config-nav-link ${activeSection === 'account' ? 'active' : ''}`}
            >
              {t('config.account')}
            </button>
            <button
              onClick={() => handleSectionChange('notifications')}
              className={`config-nav-link ${activeSection === 'notifications' ? 'active' : ''}`}
            >
              {t('config.notifications')}
            </button>
          </nav>
        </div>

        <div className="config-content">
          {activeSection === 'dashboard' && (
            <div className="config-dashboard">
              <h3>{t('config.dashboard')}</h3>
              <div className="dashboard-grid">
                <div className="dashboard-card">
                  <div className="dashboard-card-header">
                    <h4>{t('config.database')}</h4>
                  </div>
                  <div className="dashboard-card-content">
                    {loadingDbInfo ? (
                      <p className="config-description">{t('config.loadingInfo')}</p>
                    ) : dbInfo ? (
                      <>
                        <div className="dashboard-stat">
                          <span className="stat-label">{t('config.totalProducts')}</span>
                          <span className="stat-value">{dbInfo.productCount}</span>
                        </div>
                        <div className="dashboard-stat">
                          <span className="stat-label">{t('config.databaseSize')}</span>
                          <span className="stat-value">{dbInfo.databaseSizeFormatted}</span>
                        </div>
                      </>
                    ) : (
                      <p className="config-description">{t('config.unableToLoad')}</p>
                    )}
                  </div>
                  <div className="dashboard-card-actions">
                    <button
                      onClick={() => handleSectionChange('database')}
                      className="dashboard-action-button"
                    >
                      {t('config.viewDetails')}
                    </button>
                  </div>
                </div>

                <div className="dashboard-card">
                  <div className="dashboard-card-header">
                    <h4>{t('config.dataExport')}</h4>
                  </div>
                  <div className="dashboard-card-content">
                    <p className="config-description">
                      {t('config.exportDescription')}
                    </p>
                  </div>
                  <div className="dashboard-card-actions">
                    <button
                      onClick={() => handleSectionChange('data-export')}
                      className="dashboard-action-button"
                    >
                      {t('config.exportData')}
                    </button>
                  </div>
                </div>

                <div className="dashboard-card">
                  <div className="dashboard-card-header">
                    <h4>{t('config.account')}</h4>
                  </div>
                  <div className="dashboard-card-content">
                    <p className="config-description">
                      {t('config.accountDescription')}
                    </p>
                  </div>
                  <div className="dashboard-card-actions">
                    <button
                      onClick={() => handleSectionChange('account')}
                      className="dashboard-action-button"
                    >
                      {t('config.manageAccount')}
                    </button>
                  </div>
                </div>
              </div>
            </div>
          )}

          {activeSection === 'database' && (
            <div id="database" className="config-section">
            <h3>{t('config.database')}</h3>
            <div className="database-info">
              {loadingDbInfo ? (
                <p className="config-description">{t('config.loadingInfo')}</p>
              ) : dbInfo ? (
                <>
                  <div className="database-stat">
                    <span className="stat-label">{t('config.totalProducts')}</span>
                    <span className="stat-value">{dbInfo.productCount}</span>
                  </div>
                  <div className="database-stat">
                    <span className="stat-label">{t('config.databaseSize')}</span>
                    <span className="stat-value">{dbInfo.databaseSizeFormatted}</span>
                  </div>
                </>
              ) : (
                <p className="config-description">{t('config.unableToLoad')}</p>
              )}
            </div>
            <div className="config-actions">
              <button
                onClick={handleExportDatabase}
                disabled={exportingDb || loadingDbInfo}
                className="export-button"
              >
                {exportingDb ? t('config.exportingDatabase') : t('config.exportDatabase')}
              </button>
              <p className="config-description">
                {t('config.exportDatabaseDescription')}
              </p>
            </div>
            </div>
          )}

          {activeSection === 'data-export' && (
            <div id="data-export" className="config-section">
            <h3>{t('config.dataExport')}</h3>
            <div className="config-actions">
              <button
                onClick={handleExportASINs}
                disabled={exporting}
                className="export-button"
              >
                {exporting ? t('config.exportingASINs') : t('config.exportASINs')}
              </button>
              <p className="config-description">
                {t('config.exportASINsDescription')}
              </p>
            </div>
            </div>
          )}

          {activeSection === 'account' && (
            <div id="account" className="config-section">
            <h3>{t('config.account')}</h3>
            {user && (
              <div className="account-info-card">
                <div className="account-info-row">
                  <span className="account-info-label">{t('config.username')}</span>
                  <span className="account-info-value">{user.username}</span>
                </div>
                <div className="account-info-row">
                  <span className="account-info-label">{t('config.role')}</span>
                  <span className={`role-badge role-${user.role?.toLowerCase()}`}>{user.role}</span>
                </div>
                <div className="account-info-row">
                  <span className="account-info-label">{t('config.memberSince')}</span>
                  <span className="account-info-value">{new Date(user.created_at).toLocaleDateString()}</span>
                </div>
              </div>
            )}
            <form onSubmit={handleChangePassword} className="password-change-form">
              <div className="form-group">
                <label htmlFor="currentPassword">{t('config.currentPassword')}</label>
                <input
                  type="password"
                  id="currentPassword"
                  value={passwordForm.currentPassword}
                  onChange={(e) => setPasswordForm({ ...passwordForm, currentPassword: e.target.value })}
                  required
                  disabled={changingPassword}
                />
              </div>
              <div className="form-group">
                <label htmlFor="newPassword">{t('config.newPassword')}</label>
                <input
                  type="password"
                  id="newPassword"
                  value={passwordForm.newPassword}
                  onChange={(e) => setPasswordForm({ ...passwordForm, newPassword: e.target.value })}
                  required
                  minLength={6}
                  disabled={changingPassword}
                />
              </div>
              <div className="form-group">
                <label htmlFor="confirmPassword">{t('config.confirmPassword')}</label>
                <input
                  type="password"
                  id="confirmPassword"
                  value={passwordForm.confirmPassword}
                  onChange={(e) => setPasswordForm({ ...passwordForm, confirmPassword: e.target.value })}
                  required
                  minLength={6}
                  disabled={changingPassword}
                />
              </div>
              <button
                type="submit"
                disabled={changingPassword}
                className="change-password-button"
              >
                {changingPassword ? t('config.changingPassword') : t('config.changePassword')}
              </button>
              {passwordSuccess && <div className="success-message">{passwordSuccess}</div>}
            </form>
          </div>
          )}

          {error && <div className="error-message">{error}</div>}
        </div>
      </div>

      {showConfirmDialog && (
        <div className="confirm-dialog-overlay">
          <div className="confirm-dialog">
            <h3>{t('config.unsavedChanges')}</h3>
            <p>{t('config.unsavedChangesMessage')}</p>
            <div className="confirm-dialog-actions">
              <button
                onClick={handleCancelNavigation}
                className="confirm-dialog-button cancel"
              >
                {t('config.cancel')}
              </button>
              <button
                onClick={handleConfirmNavigation}
                className="confirm-dialog-button confirm"
              >
                {t('config.discardChanges')}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

