import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useAuth } from '../contexts/AuthContext';
import { api } from '../services/api';

type TabType = 'channels' | 'rules' | 'history';

export function Notifications() {
  const { t } = useTranslation();
  const { user } = useAuth();
  const [activeTab, setActiveTab] = useState<TabType>('channels');
  const [loading, setLoading] = useState(false);
  const [showChannelForm, setShowChannelForm] = useState(false);
  const [showRuleForm, setShowRuleForm] = useState(false);
  const [editingChannel, setEditingChannel] = useState<any>(null);
  const [editingRule, setEditingRule] = useState<any>(null);

  // Load data based on active tab
  useEffect(() => {
    loadData();
  }, [activeTab]);

  const loadData = async () => {
    if (!user) return;
    setLoading(true);
    try {
      switch (activeTab) {
        case 'channels':
          await api.notifications.getChannels();
          break;
        case 'rules':
          await api.notifications.getRules();
          break;
        case 'history':
          await api.notifications.getHistory(100);
          break;
      }
    } catch (error) {
      console.error('Failed to load notifications:', error);
    } finally {
      setLoading(false);
    }
  };

  const channels = [
    { id: 1, type: 'email', name: 'Work Email', enabled: true },
    { id: 2, type: 'telegram', name: 'Personal Telegram', enabled: false },
  ];

  const rules = [
    { id: 1, type: 'lowest_in_days', enabled: true },
    { id: 2, type: 'below_threshold', enabled: false },
  ];

  const history = [
    { id: 1, status: 'sent', channel_name: 'Work Email', product_description: 'Test Product' },
  ];

  const handleCreateChannel = async (data: any) => {
    try {
      await api.notifications.createChannel(data);
      setShowChannelForm(false);
      loadData();
    } catch (error: any) {
      alert(t('notifications.channels.createFailed') + ': ' + (error as Error).message);
    }
  };

  const handleUpdateChannel = async (data: any) => {
    try {
      await api.notifications.updateChannel(editingChannel.id, data);
      setShowChannelForm(false);
      setEditingChannel(null);
      loadData();
    } catch (error: any) {
      alert(t('notifications.channels.updateFailed') + ': ' + (error as Error).message);
    }
  };

  const handleDeleteChannel = async (id: number) => {
    if (!confirm(t('notifications.channels.confirmDelete'))) return;
    try {
      await api.notifications.deleteChannel(id);
      loadData();
    } catch (error: any) {
      alert(t('notifications.channels.deleteFailed') + ': ' + (error as Error).message);
    }
  };

  const handleTestChannel = async (id: number) => {
    try {
      const result = await api.notifications.testChannel(id);
      if (result.success) {
        alert(t('notifications.channels.testSuccess'));
      } else {
        alert(t('notifications.channels.testFailed') + ': ' + result.error);
      }
    } catch (error: any) {
      alert('Failed to test channel: ' + error);
    }
  };

  const handleCreateRule = async (data: any) => {
    try {
      await api.notifications.createRule(data);
      setShowRuleForm(false);
      loadData();
    } catch (error: any) {
      alert(t('notifications.rules.createFailed') + ': ' + (error as Error).message);
    }
  };

  const handleUpdateRule = async (data: any) => {
    try {
      await api.notifications.updateRule(editingRule.id, data);
      setShowRuleForm(false);
      setEditingRule(null);
      loadData();
    } catch (error: any) {
      alert(t('notifications.rules.updateFailed') + ': ' + (error as Error).message);
    }
  };

  const handleDeleteRule = async (id: number) => {
    if (!confirm(t('notifications.rules.confirmDelete'))) return;
    try {
      await api.notifications.deleteRule(id);
      loadData();
    } catch (error: any) {
      alert(t('notifications.rules.deleteFailed') + ': ' + (error as Error).message);
    }
  };

  if (!user) {
    return <div className="notifications-section">
      <p>{t('notifications.pleaseLogin')}</p>
    </div>;
  }

  return (
    <div className="notifications-section">
      <h2>{t('notifications.title')}</h2>

      {/* Tabs */}
      <nav className="notifications-tabs">
        <button
          className={`notifications-tab ${activeTab === 'channels' ? 'active' : ''}`}
          onClick={() => setActiveTab('channels')}
        >
          {t('notifications.channels.title')}
        </button>
        <button
          className={`notifications-tab ${activeTab === 'rules' ? 'active' : ''}`}
          onClick={() => setActiveTab('rules')}
        >
          {t('notifications.rules.title')}
        </button>
        <button
          className={`notifications-tab ${activeTab === 'history' ? 'active' : ''}`}
          onClick={() => setActiveTab('history')}
        >
          {t('notifications.history.title')}
        </button>
      </nav>

      {loading ? (
        <div className="loading">{t('common.loading')}</div>
      ) : (
        <>
          {/* Channels Tab */}
          {activeTab === 'channels' && (
            <div className="notifications-content">
